// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.Difference;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Union;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

class LeoOperatorKeyTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void alphaEquivalentJoinSurfacesHaveSameStructuralKey() {
		Join first = new Join(
				pattern("a", "urn:knows", "b"),
				pattern("b", "urn:knows", "c"));
		Join second = new Join(
				pattern("x", "urn:knows", "y"),
				pattern("y", "urn:knows", "z"));

		assertEquals(LeoOperatorKey.from(first), LeoOperatorKey.from(second));
	}

	@Test
	void differentConstantsChangeTheStructuralKey() {
		Join knows = new Join(
				pattern("a", "urn:knows", "b"),
				pattern("b", "urn:knows", "c"));
		Join likes = new Join(
				pattern("a", "urn:likes", "b"),
				pattern("b", "urn:knows", "c"));

		assertNotEquals(LeoOperatorKey.from(knows), LeoOperatorKey.from(likes));
	}

	@Test
	void differentJoinConnectivityChangesTheStructuralKey() {
		Join connected = new Join(
				pattern("a", "urn:knows", "b"),
				pattern("b", "urn:knows", "c"));
		Join disconnected = new Join(
				pattern("a", "urn:knows", "b"),
				pattern("c", "urn:knows", "d"));

		assertNotEquals(LeoOperatorKey.from(connected), LeoOperatorKey.from(disconnected));
	}

	@Test
	void valuesKeyPreservesArityAndDuplicateMultiplicity() {
		BindingSetAssignment unaryDuplicate = values(List.of(row("x", "urn:1"), row("x", "urn:1")));
		BindingSetAssignment unaryFreshObjects = values(List.of(row("x", "urn:1"), row("x", "urn:1")));
		BindingSetAssignment unarySingle = values(List.of(row("x", "urn:1")));
		BindingSetAssignment binarySingle = values(List.of(row("x", "urn:1", "y", "urn:2")));

		assertEquals(LeoOperatorKey.from(unaryDuplicate), LeoOperatorKey.from(unaryFreshObjects));
		assertNotEquals(LeoOperatorKey.from(unaryDuplicate), LeoOperatorKey.from(unarySingle));
		assertNotEquals(LeoOperatorKey.from(unarySingle), LeoOperatorKey.from(binarySingle));
	}

	@Test
	void unionBranchOrderDoesNotAffectKey() {
		StatementPattern left = pattern("s", "urn:left", "o");
		StatementPattern right = pattern("o", "urn:right", "label");

		assertEquals(LeoOperatorKey.from(new Union(left, right)),
				LeoOperatorKey.from(new Union(right.clone(), left.clone())));
	}

	@Test
	void differenceLeftRightOrderIsSignificant() {
		StatementPattern left = pattern("s", "urn:left", "o");
		StatementPattern right = pattern("o", "urn:right", "label");

		assertNotEquals(LeoOperatorKey.from(new Difference(left, right)),
				LeoOperatorKey.from(new Difference(right.clone(), left.clone())));
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var("predicate", VF.createIRI(predicate)), new Var(object));
	}

	private static BindingSetAssignment values(List<? extends BindingSet> rows) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingSets(new ArrayList<>(rows));
		return assignment;
	}

	private static MapBindingSet row(String name, String value) {
		MapBindingSet row = new MapBindingSet();
		row.addBinding(name, VF.createIRI(value));
		return row;
	}

	private static MapBindingSet row(String firstName, String firstValue, String secondName, String secondValue) {
		MapBindingSet row = row(firstName, firstValue);
		row.addBinding(secondName, VF.createIRI(secondValue));
		return row;
	}
}
